const data = $json;

const competitors = data.events?.[0]?.competitions?.[0]?.competitors || [];

if (!competitors.length) {
  throw new Error('No competitors found - check JSON path');
}

const out = [];

for (const c of competitors) {
  const athlete = c.athlete || {};
  const status = c.status || {};

  const rawScore = c.score;

  const name =
    athlete.displayName ||
    athlete.fullName ||
    athlete.shortName ||
    null;

  if (!name) continue;

  const positionRaw =
    c.curatedRank?.current ??
    c.order ??
    c.rank ??
    c.position?.displayValue ??
    c.position?.value ??
    null;

  let positionNum = null;
  if (typeof positionRaw === 'number') {
    positionNum = positionRaw;
  } else if (typeof positionRaw === 'string') {
    const cleaned = positionRaw.replace(/^T/i, '');
    const parsed = parseInt(cleaned, 10);
    positionNum = Number.isNaN(parsed) ? null : parsed;
  }

  // score can be object, string, or number depending on feed
  const scoreDisplay =
    typeof rawScore === 'object' && rawScore !== null
      ? (rawScore.displayValue ?? rawScore.value ?? rawScore.toPar ?? null)
      : rawScore ?? null;

  // try multiple locations for to-par
  const toPar =
    c.toPar ??
    (typeof rawScore === 'object' && rawScore !== null ? rawScore.toPar : null) ??
    c.statistics?.find(s =>
      ['to par', 'topar', 'score'].includes(String(s?.name || '').toLowerCase())
    )?.displayValue ??
    c.statistics?.find(s =>
      ['to par', 'topar', 'score'].includes(String(s?.name || '').toLowerCase())
    )?.value ??
    null;

  // try multiple locations for thru
  const thru =
    c.thru ??
    c.through ??
    c.holesThrough ??
    status.type?.shortDetail ??
    status.type?.detail ??
    status.displayValue ??
    null;

  let earnings = 0;
  if (c.earnings?.value != null) {
    earnings = Number(c.earnings.value);
  } else if (c.earnings != null && !Number.isNaN(Number(c.earnings))) {
    earnings = Number(c.earnings);
  }

  out.push({
    golfer_name: name,
    event_name: 'Masters',
    position_raw: positionRaw != null ? String(positionRaw) : null,
    position_num: positionNum,
    to_par: toPar != null ? String(toPar) : null,
    status: String(status.type?.state || status.displayValue || 'active').toLowerCase(),
    earnings,
    score_raw: scoreDisplay != null ? String(scoreDisplay) : null,
    thru: thru != null ? String(thru) : null,
    updated_at: new Date().toISOString(),
  });
}

return out.map(row => ({ json: row }));

const items = $input.all();

const espnRows = [];
const dbGolfers = [];

// Separate inputs
for (const item of items) {
  const row = item.json;

  if (row.golfer_name && row.event_name) {
    espnRows.push(row);
  }

  if (row.id && (row.api_name || row.golfer_name)) {
    dbGolfers.push(row);
  }
}

// Build lookup map
const golferMap = new Map();

for (const g of dbGolfers) {
  const key = (g.api_name || g.golfer_name || '').trim().toLowerCase();
  if (key) golferMap.set(key, g.id);
}

// Match ESPN → DB
const out = [];
const unmatched = [];

for (const row of espnRows) {
  const key = (row.golfer_name || '').trim().toLowerCase();
  const golferId = golferMap.get(key);

  if (!golferId) {
    unmatched.push(row.golfer_name);
    continue;
  }

  out.push({
    json: {
      golfer_id: golferId,
      event_name: row.event_name,
      position_raw: row.position_raw,
      position_num: row.position_num,
      to_par: row.to_par,
      status: row.status,
      earnings: row.earnings || 0,
      score_raw: row.score_raw,
      thru: row.thru,
      updated_at: row.updated_at,
    }
  });
}

// Debug (check this in logs if needed)
if (unmatched.length) {
  console.log('Unmatched golfers:', unmatched);
}

return out;
